import { clampBsDate, getDefaultBsDate } from "./bs-picker";
import { clampBsTime, getDefaultBsTime } from "./bs-time-picker";
import {
  BS_DATETIME_DISPLAY_PATTERN,
  BS_TIME_DISPLAY_PATTERN,
  formatBsDateTimePattern,
  formatBsTimePattern,
} from "./bs-time-picker/time/pattern";
import {
  clampBsDateTime,
  formatBsDateTime,
  fromAdDate,
  getDefaultBsDateTime,
  mergeBsDateTime,
  splitBsDateTime,
  toAdDate,
} from "./bs-time-picker/time/datetime";

export {
  BS_DATETIME_DISPLAY_PATTERN,
  BS_TIME_DISPLAY_PATTERN,
  clampBsDateTime,
  formatBsDateTime,
  formatBsDateTimePattern,
  formatBsTimePattern,
  fromAdDate,
  getDefaultBsDateTime,
  mergeBsDateTime,
  splitBsDateTime,
  toAdDate,
  getDefaultBsDate,
  getDefaultBsTime,
  clampBsDate,
  clampBsTime,
};

import {
  clampBsTime,
  formatMinuteOption,
  formatPeriodOption,
  formatTimeDigit,
  resolveDisplayHour,
  resolveDisplayPeriod,
  to12Hour,
  from12Hour,
} from '../../lib/bs-time-picker'
import type { BsLocale, BsPeriod, BsTime } from '@/lib/bs-time-picker/time/types'
import { cn } from '@/lib/utils'
import * as React from 'react'
import { Modal, Pressable, StyleSheet, View } from 'react-native'
import Animated, {
  Easing,
  useAnimatedStyle,
  useSharedValue,
  withTiming,
} from 'react-native-reanimated'
import Svg, { Circle, Line } from 'react-native-svg'
import { Text } from '@/components/ui/text'

const CLOCK_SIZE = 256
const CLOCK_RADIUS = 98
const NODE_SIZE = 40
const CENTER = CLOCK_SIZE / 2
/** Reach the center of dial labels (Material hand length). */
const HAND_RADIUS = CLOCK_RADIUS - NODE_SIZE / 2
const HAND_COLOR = 'hsl(180, 82%, 24%)'
const DIAL_TRANSITION_MS = 320

type SelectionMode = 'hour' | 'minute'

type BsTimePickerDialogProps = {
  visible: boolean
  value: BsTime
  locale: BsLocale
  is24Hour?: boolean
  title?: string
  cancelLabel: string
  confirmLabel: string
  onChange: (value: BsTime) => void
  onCancel: () => void
  onConfirm: () => void
}

/** Degrees clockwise from 12 o'clock (Material clock convention). */
function hour12ToClockDegrees(hour12: number): number {
  const normalized = hour12 === 12 ? 0 : hour12
  return normalized * 30
}

function hour24ToClockDegrees(hour24: number): number {
  return (hour24 / 24) * 360
}

function minuteToClockDegrees(minute: number): number {
  return (minute / 60) * 360
}

function positionForClockDegrees(clockDegrees: number, radius: number) {
  const radians = (clockDegrees - 90) * (Math.PI / 180)
  return {
    left: CENTER + radius * Math.cos(radians) - NODE_SIZE / 2,
    top: CENTER + radius * Math.sin(radians) - NODE_SIZE / 2,
  }
}

function getHourDialValues(is24Hour: boolean): number[] {
  return is24Hour
    ? Array.from({ length: 24 }, (_, index) => index)
    : Array.from({ length: 12 }, (_, index) => index + 1)
}

function getMinuteDialValues(): number[] {
  return Array.from({ length: 12 }, (_, index) => index * 5)
}

function isMinuteDialSelected(dialValue: number, selectedMinute: number): boolean {
  return (
    Math.abs(dialValue - selectedMinute) < 3 ||
    (selectedMinute >= 58 && dialValue === 0)
  )
}

function resolveSelectedMinuteDial(minute: number): number {
  return (
    getMinuteDialValues().find((dialValue) =>
      isMinuteDialSelected(dialValue, minute),
    ) ?? 0
  )
}

function hourValueToClockDegrees(hour: number, is24Hour: boolean): number {
  return is24Hour ? hour24ToClockDegrees(hour) : hour12ToClockDegrees(hour)
}

function minuteValueToClockDegrees(minute: number): number {
  return minuteToClockDegrees(minute)
}

function clockHandEnd(clockDegrees: number, radius: number) {
  const radians = (clockDegrees - 90) * (Math.PI / 180)
  return {
    x: CENTER + radius * Math.cos(radians),
    y: CENTER + radius * Math.sin(radians),
  }
}

type BsTimePickerClockProps = {
  mode: SelectionMode
  value: BsTime
  locale: BsLocale
  is24Hour: boolean
  onSelectHour: (hour: number) => void
  onSelectMinute: (minute: number) => void
}

function ClockHand({ clockDegrees }: { clockDegrees: number }) {
  const end = clockHandEnd(clockDegrees, HAND_RADIUS)

  return (
    <Svg
      width={CLOCK_SIZE}
      height={CLOCK_SIZE}
      pointerEvents="none"
      style={{ position: 'absolute', left: 0, top: 0, zIndex: 1 }}
    >
      <Line
        x1={CENTER}
        y1={CENTER}
        x2={end.x}
        y2={end.y}
        stroke={HAND_COLOR}
        strokeWidth={2}
        strokeLinecap="round"
      />
      <Circle cx={CENTER} cy={CENTER} r={5} fill={HAND_COLOR} />
    </Svg>
  )
}

type ClockDialNodesProps = {
  mode: SelectionMode
  value: BsTime
  locale: BsLocale
  is24Hour: boolean
  onSelectHour: (hour: number) => void
  onSelectMinute: (minute: number) => void
}

function ClockDialNodes({
  mode,
  value,
  locale,
  is24Hour,
  onSelectHour,
  onSelectMinute,
}: ClockDialNodesProps) {
  const dialValues =
    mode === 'hour' ? getHourDialValues(is24Hour) : getMinuteDialValues()

  const selectedHour = is24Hour ? value.hour : resolveDisplayHour(value.hour, false)
  const selectedMinute = value.minute

  return (
    <>
      {dialValues.map((dialValue) => {
        const clockDegrees =
          mode === 'hour'
            ? hourValueToClockDegrees(dialValue, is24Hour)
            : minuteValueToClockDegrees(dialValue)

        const isSelected =
          mode === 'hour'
            ? dialValue === selectedHour
            : isMinuteDialSelected(dialValue, selectedMinute)

        const position = positionForClockDegrees(clockDegrees, CLOCK_RADIUS)
        const label =
          mode === 'hour'
            ? formatTimeDigit(dialValue, locale)
            : formatMinuteOption(dialValue, locale)

        return (
          <Pressable
            key={`${mode}-${dialValue}`}
            className={cn(
              'absolute z-20 items-center justify-center rounded-full',
              isSelected ? 'bg-primary' : 'bg-transparent',
            )}
            style={{
              left: position.left,
              top: position.top,
              width: NODE_SIZE,
              height: NODE_SIZE,
            }}
            onPress={() => {
              if (mode === 'hour') {
                if (is24Hour) {
                  onSelectHour(dialValue)
                } else {
                  const period = resolveDisplayPeriod(value.hour, false)
                  onSelectHour(from12Hour(dialValue, period))
                }
              } else {
                onSelectMinute(dialValue)
              }
            }}
          >
            <Text
              className={cn(
                'text-sm font-medium',
                isSelected ? 'text-primary-foreground' : 'text-foreground',
              )}
            >
              {label}
            </Text>
          </Pressable>
        )
      })}
    </>
  )
}

type ClockDialLayerProps = {
  mode: SelectionMode
  value: BsTime
  locale: BsLocale
  is24Hour: boolean
  handClockDegrees: number
  onSelectHour: (hour: number) => void
  onSelectMinute: (minute: number) => void
}

function ClockDialLayer({
  mode,
  value,
  locale,
  is24Hour,
  handClockDegrees,
  onSelectHour,
  onSelectMinute,
}: ClockDialLayerProps) {
  return (
    <>
      <ClockHand clockDegrees={handClockDegrees} />
      <ClockDialNodes
        mode={mode}
        value={value}
        locale={locale}
        is24Hour={is24Hour}
        onSelectHour={onSelectHour}
        onSelectMinute={onSelectMinute}
      />
    </>
  )
}

function BsTimePickerClock({
  mode,
  value,
  locale,
  is24Hour,
  onSelectHour,
  onSelectMinute,
}: BsTimePickerClockProps) {
  const selectedHour = is24Hour ? value.hour : resolveDisplayHour(value.hour, false)
  const selectedMinute = value.minute
  const dialProgress = useSharedValue(mode === 'hour' ? 0 : 1)
  const hasAnimatedDial = React.useRef(false)

  React.useEffect(() => {
    const target = mode === 'hour' ? 0 : 1
    if (!hasAnimatedDial.current) {
      dialProgress.value = target
      hasAnimatedDial.current = true
      return
    }

    dialProgress.value = withTiming(target, {
      duration: DIAL_TRANSITION_MS,
      easing: Easing.inOut(Easing.cubic),
    })
  }, [dialProgress, mode])

  const hourDialStyle = useAnimatedStyle(() => ({
    opacity: 1 - dialProgress.value,
    transform: [{ scale: 1 - dialProgress.value * 0.06 }],
  }))

  const minuteDialStyle = useAnimatedStyle(() => ({
    opacity: dialProgress.value,
    transform: [{ scale: 0.94 + dialProgress.value * 0.06 }],
  }))

  const hourHandDegrees = hourValueToClockDegrees(selectedHour, is24Hour)
  const minuteHandDegrees = minuteValueToClockDegrees(
    resolveSelectedMinuteDial(selectedMinute),
  )

  return (
    <View
      className="relative self-center rounded-full border border-border/70 bg-input"
      style={{ width: CLOCK_SIZE, height: CLOCK_SIZE }}
    >
      <Animated.View
        pointerEvents={mode === 'hour' ? 'auto' : 'none'}
        style={[styles.dialLayer, hourDialStyle]}
      >
        <ClockDialLayer
          mode="hour"
          value={value}
          locale={locale}
          is24Hour={is24Hour}
          handClockDegrees={hourHandDegrees}
          onSelectHour={onSelectHour}
          onSelectMinute={onSelectMinute}
        />
      </Animated.View>

      <Animated.View
        pointerEvents={mode === 'minute' ? 'auto' : 'none'}
        style={[styles.dialLayer, minuteDialStyle]}
      >
        <ClockDialLayer
          mode="minute"
          value={value}
          locale={locale}
          is24Hour={is24Hour}
          handClockDegrees={minuteHandDegrees}
          onSelectHour={onSelectHour}
          onSelectMinute={onSelectMinute}
        />
      </Animated.View>
    </View>
  )
}

const styles = StyleSheet.create({
  dialLayer: {
    ...StyleSheet.absoluteFill,
  },
})

export function BsTimePickerDialog({
  visible,
  value,
  locale,
  is24Hour = false,
  title,
  cancelLabel,
  confirmLabel,
  onChange,
  onCancel,
  onConfirm,
}: BsTimePickerDialogProps) {
  const [selectionMode, setSelectionMode] = React.useState<SelectionMode>('hour')
  const clamped = clampBsTime(value)
  const displayHour = resolveDisplayHour(clamped.hour, is24Hour)
  const displayPeriod = resolveDisplayPeriod(clamped.hour, is24Hour)

  const updateTime = (patch: Partial<BsTime>) => {
    onChange(clampBsTime({ ...clamped, ...patch }))
  }

  const setPeriod = (period: BsPeriod) => {
    const { hour: hour12 } = to12Hour(clamped.hour)
    updateTime({ hour: from12Hour(hour12, period) })
  }

  const handleSelectHour = (hour24: number) => {
    updateTime({ hour: hour24 })
    setSelectionMode('minute')
  }

  if (!visible) return null

  return (
    <Modal visible transparent animationType="fade" onRequestClose={onCancel}>
      <Pressable
        className="flex-1 items-center justify-center bg-black/50 px-5 py-6"
        onPress={onCancel}
      >
        <Pressable
          className="w-full max-w-[360px] overflow-hidden rounded-[28px] bg-background"
          onPress={(event) => event.stopPropagation()}
        >
          {title ? (
            <View className="px-6 pb-2 pt-6">
              <Text className="text-sm font-medium text-muted-foreground">
                {title}
              </Text>
            </View>
          ) : null}

          <View className="flex-row items-center px-6 pb-4 pt-4">
            <View className="flex-1 flex-row items-center gap-2">
              <Pressable
                className={cn(
                  'min-w-[72px] rounded-xl px-3 py-3',
                  selectionMode === 'hour' ? 'bg-primary/15' : 'bg-input',
                )}
                onPress={() => setSelectionMode('hour')}
              >
                <Text className="text-center text-[44px] leading-none text-foreground">
                  {formatTimeDigit(displayHour, locale)}
                </Text>
              </Pressable>

              <Text className="text-[44px] leading-none text-muted-foreground">
                :
              </Text>

              <Pressable
                className={cn(
                  'min-w-[72px] rounded-xl px-3 py-3',
                  selectionMode === 'minute' ? 'bg-primary/15' : 'bg-input',
                )}
                onPress={() => setSelectionMode('minute')}
              >
                <Text className="text-center text-[44px] leading-none text-foreground">
                  {formatMinuteOption(clamped.minute, locale)}
                </Text>
              </Pressable>
            </View>

            {!is24Hour ? (
              <View className="ml-3 overflow-hidden rounded-xl border border-border/60">
                <Pressable
                  className={cn(
                    'min-w-12 items-center px-3 py-2',
                    displayPeriod === 'am' ? 'bg-primary/15' : 'bg-transparent',
                  )}
                  onPress={() => setPeriod('am')}
                >
                  <Text className="text-xs font-semibold uppercase text-foreground">
                    {formatPeriodOption('am', locale)}
                  </Text>
                </Pressable>
                <Pressable
                  className={cn(
                    'min-w-12 items-center px-3 py-2',
                    displayPeriod === 'pm' ? 'bg-primary/15' : 'bg-transparent',
                  )}
                  onPress={() => setPeriod('pm')}
                >
                  <Text className="text-xs font-semibold uppercase text-foreground">
                    {formatPeriodOption('pm', locale)}
                  </Text>
                </Pressable>
              </View>
            ) : null}
          </View>

          <View className="items-center px-4 pb-4 pt-1">
            <BsTimePickerClock
              mode={selectionMode}
              value={clamped}
              locale={locale}
              is24Hour={is24Hour}
              onSelectHour={handleSelectHour}
              onSelectMinute={(minute) => updateTime({ minute })}
            />
          </View>

          <View className="flex-row justify-end px-2 pb-3 pt-1">
            <Pressable
              className="min-h-12 items-center justify-center px-4"
              onPress={onCancel}
            >
              <Text className="text-sm font-semibold uppercase text-primary">
                {cancelLabel}
              </Text>
            </Pressable>
            <Pressable
              className="min-h-12 items-center justify-center px-4"
              onPress={onConfirm}
            >
              <Text className="text-sm font-semibold uppercase text-primary">
                {confirmLabel}
              </Text>
            </Pressable>
          </View>
        </Pressable>
      </Pressable>
    </Modal>
  )
}

import { Text } from '@/components/ui/text'
import { cn } from '@/lib/utils'
import * as Haptics from 'expo-haptics'
import * as React from 'react'
import {
  FlatList,
  Platform,
  useColorScheme,
  type ListRenderItemInfo,
  type NativeScrollEvent,
  type NativeSyntheticEvent,
  Pressable,
  View,
} from 'react-native'

const ITEM_HEIGHT = Platform.OS === 'ios' ? 44 : 48
const VISIBLE_COUNT = 5
export const BS_WHEEL_HEIGHT = ITEM_HEIGHT * VISIBLE_COUNT
const EDGE_PADDING = ITEM_HEIGHT * Math.floor(VISIBLE_COUNT / 2)
const DEFAULT_LOOP_REPEATS = 51
/** iOS UIDatePicker-style selection band height (44pt row). */
export const BS_WHEEL_SELECTION_HEIGHT = ITEM_HEIGHT
/** Horizontal padding beyond measured column edges. */
const BS_WHEEL_PILL_H_PAD = 6

function wheelItemOpacity(distance: number): number {
  if (distance <= 0) return 1
  if (distance === 1) return 0.48
  if (distance === 2) return 0.28
  return 0.14
}

/** Gap between wheel columns (native UIDatePicker is tight). */
export const BS_WHEEL_COLUMN_GAP = 6
export const BS_WHEEL_DATE_COL_WIDTH = 172
export const BS_WHEEL_HOUR_COL_WIDTH = 46
export const BS_WHEEL_MIN_COL_WIDTH = 46
export const BS_WHEEL_PERIOD_COL_WIDTH = 50

function triggerWheelSelectionHaptic() {
  if (Platform.OS === 'web') return
  void Haptics.selectionAsync()
}

function flattenWheelChildren(children: React.ReactNode): React.ReactNode[] {
  const nodes: React.ReactNode[] = []
  React.Children.forEach(children, (child) => {
    if (child == null || child === false) return
    if (React.isValidElement<{ children?: React.ReactNode }>(child) && child.type === React.Fragment) {
      flattenWheelChildren(child.props.children).forEach((node) => nodes.push(node))
      return
    }
    nodes.push(child)
  })
  return nodes
}

type BsWheelSelectionBandProps = {
  /** When set, pill hugs measured column group (native UIDatePicker). */
  left?: number
  width?: number
}

/** One centered pill spanning all columns (native iOS wheel — not per-column). */
export function BsWheelSelectionBand({
  left,
  width,
}: BsWheelSelectionBandProps = {}) {
  const colorScheme = useColorScheme()
  const radius = BS_WHEEL_SELECTION_HEIGHT / 2
  const top = (BS_WHEEL_HEIGHT - BS_WHEEL_SELECTION_HEIGHT) / 2
  const hugContent = width != null && width > 0 && left != null

  return (
    <View
      pointerEvents="none"
      style={{
        position: 'absolute',
        zIndex: 1,
        top,
        ...(hugContent
          ? {
              left: left - BS_WHEEL_PILL_H_PAD,
              width: width + BS_WHEEL_PILL_H_PAD * 2,
            }
          : {
              left: BS_WHEEL_PILL_H_PAD,
              right: BS_WHEEL_PILL_H_PAD,
            }),
        height: BS_WHEEL_SELECTION_HEIGHT,
        borderRadius: radius,
        backgroundColor:
          colorScheme === 'dark'
            ? 'rgba(120, 120, 128, 0.36)'
            : 'rgba(120, 120, 128, 0.24)',
      }}
    />
  )
}

type BsWheelRowProps = {
  children: React.ReactNode
  className?: string
  /** Show the shared selection band (default true for multi-column rows). */
  showSelectionBand?: boolean
  /** Gap between column groups (default BS_WHEEL_COLUMN_GAP). */
  columnGap?: number
}

type BsWheelRowMeasuredProps = {
  flatChildren: React.ReactNode[]
  showSelectionBand: boolean
  columnGap: number
}

function BsWheelRowMeasured({
  flatChildren,
  showSelectionBand,
  columnGap,
}: BsWheelRowMeasuredProps) {
  const childLayouts = React.useRef<Array<{ x: number; width: number }>>([])
  const [pillBox, setPillBox] = React.useState({ left: 0, width: 0 })

  const updatePillBox = React.useCallback(() => {
    const layouts = childLayouts.current
    if (layouts.length < flatChildren.length) return
    if (layouts.some((layout) => layout == null || layout.width <= 0)) return

    const left = Math.min(...layouts.map((layout) => layout.x))
    const right = Math.max(...layouts.map((layout) => layout.x + layout.width))
    setPillBox({ left, width: right - left })
  }, [flatChildren.length])

  const wrappedChildren = flatChildren.map((child, index) => (
    <View
      key={index}
      collapsable={false}
      onLayout={(event) => {
        const { x, width } = event.nativeEvent.layout
        childLayouts.current[index] = { x, width }
        updatePillBox()
      }}
    >
      {child}
    </View>
  ))

  return (
    <View className="relative flex-row items-stretch" style={{ gap: columnGap }}>
      {showSelectionBand && pillBox.width > 0 ? (
        <BsWheelSelectionBand left={pillBox.left} width={pillBox.width} />
      ) : null}
      {wrappedChildren}
    </View>
  )
}

export function BsWheelRow({
  children,
  className,
  showSelectionBand = true,
  columnGap = BS_WHEEL_COLUMN_GAP,
}: BsWheelRowProps) {
  const flatChildren = React.useMemo(
    () => flattenWheelChildren(children),
    [children],
  )

  return (
    <View
      className={cn('relative w-full', className)}
      style={{ height: BS_WHEEL_HEIGHT }}
    >
      <View
        className="h-full w-full items-center justify-center"
        style={{ zIndex: 2 }}
      >
        <BsWheelRowMeasured
          key={flatChildren.length}
          flatChildren={flatChildren}
          showSelectionBand={showSelectionBand}
          columnGap={columnGap}
        />
      </View>
    </View>
  )
}

type BsWheelColumnProps<T extends string | number> = {
  items: readonly T[]
  selected: T
  onSelect: (value: T) => void
  formatLabel: (value: T) => string
  className?: string
  /** Fixed column width (preferred over Tailwind width classes). */
  columnWidth?: number
  showOverlay?: boolean
  /** Tighter horizontal padding for numeric columns. */
  compact?: boolean
  /** Repeat items and recenter while scrolling for a native infinite wheel feel. */
  loop?: boolean
  loopRepeats?: number
  /** Avoid O(n) lookup when the item list is large (e.g. chronological dates). */
  selectedIndex?: number
}

function normalizeIndex(index: number, length: number): number {
  if (length === 0) return 0
  return ((index % length) + length) % length
}

export function BsWheelColumn<T extends string | number>({
  items,
  selected,
  onSelect,
  formatLabel,
  className,
  columnWidth,
  showOverlay = true,
  compact = false,
  loop = false,
  loopRepeats = DEFAULT_LOOP_REPEATS,
  selectedIndex: selectedIndexProp,
}: BsWheelColumnProps<T>) {
  const listRef = React.useRef<FlatList<T>>(null)
  const isRecenteringRef = React.useRef(false)
  const selectedIndex = Math.max(
    0,
    selectedIndexProp ?? items.indexOf(selected),
  )
  const middleOffset =
    loop && items.length > 0
      ? Math.floor(loopRepeats / 2) * items.length
      : 0

  const data = React.useMemo(() => {
    if (!loop || items.length === 0) return [...items]
    return Array.from(
      { length: items.length * loopRepeats },
      (_, index) => items[normalizeIndex(index, items.length)]!,
    )
  }, [items, loop, loopRepeats])

  const indexForSelected = React.useCallback(
    (index: number) => (loop ? middleOffset + index : index),
    [loop, middleOffset],
  )

  const [focusedIndex, setFocusedIndex] = React.useState(() =>
    indexForSelected(selectedIndex),
  )

  const scrollToIndex = React.useCallback(
    (index: number, animated = false) => {
      if (index < 0 || index >= data.length) return
      listRef.current?.scrollToOffset({
        offset: index * ITEM_HEIGHT,
        animated,
      })
      setFocusedIndex(index)
    },
    [data.length],
  )

  const recenterIfNeeded = React.useCallback(
    (index: number) => {
      if (!loop || items.length === 0) return index

      const edgeBuffer = items.length * 2
      if (index >= edgeBuffer && index < data.length - edgeBuffer) {
        return index
      }

      const normalizedIndex = normalizeIndex(index, items.length)
      const targetIndex = middleOffset + normalizedIndex
      isRecenteringRef.current = true
      listRef.current?.scrollToOffset({
        offset: targetIndex * ITEM_HEIGHT,
        animated: false,
      })
      setFocusedIndex(targetIndex)
      requestAnimationFrame(() => {
        isRecenteringRef.current = false
      })
      return targetIndex
    },
    [data.length, items.length, loop, middleOffset],
  )

  React.useEffect(() => {
    const targetIndex = indexForSelected(selectedIndex)
    // Scroll only — avoid setFocusedIndex here (react-hooks/set-state-in-effect).
    if (targetIndex < 0 || targetIndex >= data.length) return
    listRef.current?.scrollToOffset({
      offset: targetIndex * ITEM_HEIGHT,
      animated: false,
    })
  }, [data.length, indexForSelected, selectedIndex])

  const commitIndex = React.useCallback(
    (index: number) => {
      const boundedIndex = Math.min(
        data.length - 1,
        Math.max(0, Math.round(index)),
      )
      const settledIndex = recenterIfNeeded(boundedIndex)
      const normalizedIndex = loop
        ? normalizeIndex(settledIndex, items.length)
        : settledIndex
      const next = items[normalizedIndex]
      if (next !== undefined && next !== selected) {
        onSelect(next)
      }
    },
    [data.length, items, loop, onSelect, recenterIfNeeded, selected],
  )

  const handleScroll = (event: NativeSyntheticEvent<NativeScrollEvent>) => {
    if (isRecenteringRef.current) return

    const index = Math.min(
      data.length - 1,
      Math.max(0, Math.round(event.nativeEvent.contentOffset.y / ITEM_HEIGHT)),
    )

    if (index !== focusedIndex) {
      triggerWheelSelectionHaptic()
      setFocusedIndex(index)
    }
  }

  const handleMomentumEnd = (offsetY: number) => {
    commitIndex(offsetY / ITEM_HEIGHT)
  }

  const renderItem = ({ item, index }: ListRenderItemInfo<T>) => {
    const distance = Math.abs(index - focusedIndex)
    const opacity = wheelItemOpacity(distance)
    const isFocused = distance === 0
    return (
      <Pressable
        className={cn(
          'w-full items-center justify-center',
          compact ? 'px-0' : 'px-1',
        )}
        style={{ height: ITEM_HEIGHT }}
        onPress={() => {
          triggerWheelSelectionHaptic()
          scrollToIndex(index, true)
          const normalizedIndex = loop
            ? normalizeIndex(index, items.length)
            : index
          const next = items[normalizedIndex]
          if (next !== undefined) {
            onSelect(next)
          }
        }}
      >
        <Text
          className={cn(
            'w-full text-center text-[20px] leading-[25px]',
            isFocused ? 'font-semibold text-foreground' : 'font-normal text-foreground',
          )}
          style={{ opacity }}
          numberOfLines={1}
          adjustsFontSizeToFit
          minimumFontScale={0.8}
        >
          {formatLabel(item)}
        </Text>
      </Pressable>
    )
  }

  return (
    <View
      className={cn('relative shrink-0', className)}
      style={{
        width: columnWidth,
        height: BS_WHEEL_HEIGHT,
        backgroundColor: 'transparent',
      }}
    >
      {showOverlay ? <BsWheelSelectionBand /> : null}
      <FlatList
        ref={listRef}
        data={data}
        style={{ flex: 1, backgroundColor: 'transparent', zIndex: 2 }}
        initialScrollIndex={
          data.length > 0 ? Math.min(focusedIndex, data.length - 1) : undefined
        }
        keyExtractor={(item, index) => `${String(item)}-${index}`}
        renderItem={renderItem}
        showsVerticalScrollIndicator={false}
        snapToInterval={ITEM_HEIGHT}
        decelerationRate="fast"
        getItemLayout={(_, index) => ({
          length: ITEM_HEIGHT,
          offset: ITEM_HEIGHT * index,
          index,
        })}
        contentContainerStyle={{ paddingVertical: EDGE_PADDING }}
        onScroll={handleScroll}
        scrollEventThrottle={16}
        onMomentumScrollEnd={(event) =>
          handleMomentumEnd(event.nativeEvent.contentOffset.y)
        }
        onScrollEndDrag={(event) => {
          if (event.nativeEvent.velocity?.y === 0) {
            handleMomentumEnd(event.nativeEvent.contentOffset.y)
          }
        }}
      />
    </View>
  )
}

import {
  clampBsDate,
  formatBsDateWheelKey,
  getBsDateWheelKeys,
  parseBsDateWheelKey,
} from '@/lib/bs-picker'
import { getBsDateIndex } from '@/lib/bs-day-picker/navigation'
import { bsDateKey } from '@/lib/bs-day-picker/types'
import type { BsDate, BsLocale } from '@/lib/bs-day-picker/types'
import {
  clampBsTime,
  formatHourOption,
  formatMinuteOption,
  formatPeriodOption,
  getHourOptions,
  getMinuteOptions,
  getPeriodOptions,
  resolveDisplayHour,
  resolveDisplayPeriod,
  resolveWheelHour,
} from '../../lib/bs-time-picker'
import type { BsDateTime, BsPeriod, BsTime } from '@/lib/bs-time-picker/time/types'
import { mergeBsDateTime, splitBsDateTime } from '../../lib/bs-datetime-picker'
import {
  BS_WHEEL_DATE_COL_WIDTH,
  BS_WHEEL_HOUR_COL_WIDTH,
  BS_WHEEL_MIN_COL_WIDTH,
  BS_WHEEL_PERIOD_COL_WIDTH,
  BsWheelColumn,
  BsWheelRow,
} from './bs-wheel-column'

type BsDateTimePickerWheelsProps = {
  value: BsDateTime
  locale: BsLocale
  is24Hour?: boolean
  onChange: (value: BsDateTime) => void
}

export function BsDateTimePickerWheels({
  value,
  locale,
  is24Hour = false,
  onChange,
}: BsDateTimePickerWheelsProps) {
  const { date, time } = splitBsDateTime(value)
  const dateKeys = getBsDateWheelKeys()
  const clampedDate = clampBsDate(date)
  const clampedTime = clampBsTime(time)
  const selectedKey = bsDateKey(clampedDate)
  const selectedIndex = getBsDateIndex(clampedDate)

  const hourOptions = getHourOptions(is24Hour)
  const minuteOptions = getMinuteOptions()
  const periodOptions = getPeriodOptions()
  const displayHour = resolveDisplayHour(clampedTime.hour, is24Hour)
  const displayPeriod = resolveDisplayPeriod(clampedTime.hour, is24Hour)

  const handleDateChange = (nextDate: BsDate) => {
    onChange(mergeBsDateTime(clampBsDate(nextDate), clampedTime))
  }

  const updateTime = (
    nextHour: number,
    nextMinute: number,
    nextPeriod: BsPeriod,
  ) => {
    const nextTime: BsTime = clampBsTime({
      hour: resolveWheelHour(nextHour, nextPeriod, is24Hour),
      minute: nextMinute,
    })
    onChange(mergeBsDateTime(clampedDate, nextTime))
  }

  return (
    <BsWheelRow>
      <BsWheelColumn
        showOverlay={false}
        columnWidth={BS_WHEEL_DATE_COL_WIDTH}
        items={dateKeys}
        selected={selectedKey}
        selectedIndex={selectedIndex >= 0 ? selectedIndex : undefined}
        onSelect={(key) => {
          const next = parseBsDateWheelKey(key)
          if (next) handleDateChange(clampBsDate(next))
        }}
        formatLabel={(key) => formatBsDateWheelKey(key, locale)}
      />
      <BsWheelColumn
        showOverlay={false}
        compact
        columnWidth={BS_WHEEL_HOUR_COL_WIDTH}
        items={hourOptions}
        selected={displayHour}
        onSelect={(hour) => updateTime(hour, clampedTime.minute, displayPeriod)}
        formatLabel={(hour) => formatHourOption(hour, locale, is24Hour)}
        loop
      />
      <BsWheelColumn
        showOverlay={false}
        compact
        columnWidth={BS_WHEEL_MIN_COL_WIDTH}
        items={minuteOptions}
        selected={clampedTime.minute}
        onSelect={(minute) => updateTime(displayHour, minute, displayPeriod)}
        formatLabel={(minute) => formatMinuteOption(minute, locale)}
        loop
      />
      {!is24Hour ? (
        <BsWheelColumn
          showOverlay={false}
          compact
          columnWidth={BS_WHEEL_PERIOD_COL_WIDTH}
          items={periodOptions}
          selected={displayPeriod}
          onSelect={(period) =>
            updateTime(displayHour, clampedTime.minute, period)
          }
          formatLabel={(period) => formatPeriodOption(period, locale)}
        />
      ) : null}
    </BsWheelRow>
  )
}

import {
  formatBsDateTime,
  getDefaultBsDateTime,
} from "../../lib/bs-datetime-picker";
import { formatBsDateTimePattern } from "@/lib/bs-time-picker/time/pattern";
import type { BsDateTime, BsLocale } from "@/lib/bs-time-picker/time/types";
import { cn } from "@/lib/utils";
import { CalendarClock } from "lucide-react-native";
import * as React from "react";
import { Modal, TouchableWithoutFeedback, View } from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { BsDateTimePickerWheels } from "./bs-datetime-picker-wheels.ios";
import { BsWheelSheetChrome } from "./bs-wheel-sheet";
import { Button } from "@/components/ui/button";
import { Icon } from "@/components/ui/icon";
import { Text } from "@/components/ui/text";

export type BsDateTimePickerProps = {
  value?: BsDateTime;
  onValueChange?: (value: BsDateTime | undefined) => void;
  locale?: BsLocale;
  is24Hour?: boolean;
  placeholder?: string;
  cancelLabel?: string;
  confirmLabel?: string;
  formatPattern?: string;
  formatValue?: (
    value: BsDateTime,
    locale: BsLocale,
    is24Hour: boolean,
  ) => string;
  className?: string;
  disabled?: boolean;
};

function resolveDateTimeDisplayLabel(
  value: BsDateTime,
  locale: BsLocale,
  is24Hour: boolean,
  formatValue?: BsDateTimePickerProps["formatValue"],
  formatPattern?: string,
): string {
  if (formatValue) return formatValue(value, locale, is24Hour);
  if (formatPattern) {
    return formatBsDateTimePattern(value, formatPattern, locale, is24Hour);
  }
  return formatBsDateTime(value, locale, is24Hour);
}

export function BsDateTimePicker({
  value,
  onValueChange,
  locale = "ne",
  is24Hour = false,
  placeholder,
  cancelLabel,
  confirmLabel,
  formatPattern,
  formatValue,
  className,
  disabled = false,
}: BsDateTimePickerProps) {
  const insets = useSafeAreaInsets();
  const resolvedPlaceholder =
    placeholder ??
    (locale === "ne" ? "मिति र समय छान्नुहोस्" : "Select date and time");
  const resolvedCancel = cancelLabel ?? "Cancel";
  const resolvedConfirm = confirmLabel ?? "Confirm";
  const [showPicker, setShowPicker] = React.useState(false);
  const [tempValue, setTempValue] = React.useState<BsDateTime>(
    value ?? getDefaultBsDateTime(),
  );

  const handleOpen = () => {
    if (disabled) return;
    setTempValue(value ?? getDefaultBsDateTime());
    setShowPicker(true);
  };

  const handleCancel = () => {
    setShowPicker(false);
    setTempValue(value ?? getDefaultBsDateTime());
  };

  const handleConfirm = () => {
    setShowPicker(false);
    onValueChange?.(tempValue);
  };

  const displayLabel = value
    ? resolveDateTimeDisplayLabel(
        value,
        locale,
        is24Hour,
        formatValue,
        formatPattern,
      )
    : resolvedPlaceholder;

  return (
    <>
      <Button
        variant="outline"
        className={cn("justify-between", className)}
        disabled={disabled}
        onPress={handleOpen}
      >
        <Text className={cn(!value && "text-muted-foreground")}>
          {displayLabel}
        </Text>
        <Icon as={CalendarClock} className="size-4 text-muted-foreground" />
      </Button>

      <Modal visible={showPicker} transparent animationType="slide">
        <TouchableWithoutFeedback onPress={handleCancel}>
          <View className="flex-1 justify-end bg-black/70">
            <TouchableWithoutFeedback onPress={() => {}}>
              <BsWheelSheetChrome
                cancelLabel={resolvedCancel}
                confirmLabel={resolvedConfirm}
                bottomInset={insets.bottom}
                onCancel={handleCancel}
                onConfirm={handleConfirm}
              >
                <BsDateTimePickerWheels
                  value={tempValue}
                  locale={locale}
                  is24Hour={is24Hour}
                  onChange={setTempValue}
                />
              </BsWheelSheetChrome>
            </TouchableWithoutFeedback>
          </View>
        </TouchableWithoutFeedback>
      </Modal>
    </>
  );
}

import {
  getDefaultBsDateTime,
  mergeBsDateTime,
  splitBsDateTime,
  formatBsDateTime,
} from "../../lib/bs-datetime-picker";
import { formatBsDateTimePattern } from "@/lib/bs-time-picker/time/pattern";
